import { Component } from '@angular/core';
import { FormBuilder, FormGroup } from '@angular/forms';
import { Router } from '@angular/router';
import { QuoteService } from '../../services/quote.service';

@Component({
  selector: 'app-quote-create',
  templateUrl: './quote-create.component.html',
  styleUrls: ['./quote-create.component.scss']
})
export class QuoteCreateComponent {
  quoteForm: FormGroup;
  loading = false;
  error = '';
  selectedFile: File | null = null;

  constructor(
    private formBuilder: FormBuilder,
    private router: Router,
    private quoteService: QuoteService
  ) {
    this.quoteForm = this.formBuilder.group({
      description: [''],
      customerMessage: ['']
    });
  }

  onFileSelected(event: any) {
    const file = event.target.files[0];
    if (file) {
      console.log('🔍 前端文件选择:', {
        name: file.name,
        size: file.size,
        type: file.type,
        lastModified: file.lastModified,
        webkitRelativePath: (file as any).webkitRelativePath || 'N/A'
      });
      
      // 检查文件类型
      if (!file.name.endsWith('.xlsx') && !file.name.endsWith('.xls')) {
        this.error = '请选择Excel文件 (.xlsx 或 .xls)';
        event.target.value = '';
        return;
      }
      
      // 检查文件大小 (10MB限制)
      if (file.size > 10 * 1024 * 1024) {
        this.error = '文件大小不能超过10MB';
        event.target.value = '';
        return;
      }
      
      this.selectedFile = file;
      this.error = '';
    }
  }

  onSubmit() {
    if (!this.selectedFile) {
      this.error = '请选择Excel文件';
      return;
    }

    this.loading = true;
    this.error = '';

    // 从文件名生成标题（去掉扩展名）
    const fileName = this.selectedFile.name;
    const title = fileName.substring(0, fileName.lastIndexOf('.')) || fileName;

    console.log('📤 前端准备发送数据:', {
      fileName: fileName,
      title: title,
      description: this.quoteForm.get('description')?.value || '',
      customerMessage: this.quoteForm.get('customerMessage')?.value || '',
      fileSize: this.selectedFile.size,
      fileType: this.selectedFile.type
    });

    const formData = new FormData();
    
    // 确保使用UTF-8编码添加字段
    formData.append('title', title);
    formData.append('description', this.quoteForm.get('description')?.value || '');
    formData.append('customerMessage', this.quoteForm.get('customerMessage')?.value || '');
    formData.append('customerFile', this.selectedFile);

    // 调试 FormData 内容
    console.log('📤 FormData 内容:');
    for (let [key, value] of formData.entries()) {
      if (value instanceof File) {
        console.log(`  ${key}:`, {
          name: value.name,
          size: value.size,
          type: value.type
        });
      } else {
        console.log(`  ${key}:`, value);
      }
    }

    this.quoteService.createQuote(formData).subscribe({
      next: () => {
        console.log('✅ 询价单创建成功');
        this.router.navigate(['/quotes']);
      },
      error: (error) => {
        console.error('❌ 询价单创建失败:', error);
        this.error = error.error?.message || '创建询价单失败';
        this.loading = false;
      }
    });
  }
}
